package com.inventory.product.dto;
import jakarta.validation.constraints.*;
public class CategoryDto { private Long id; @NotBlank(message="Category name is required") @Size(min=3,max=100,message="Category name must be between 3 and 100 characters") private String name; @Size(max=500,message="Description cannot exceed 500 characters") private String description; public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getDescription(){return description;} public void setDescription(String description){this.description=description;} }
